package com.ichi2.anki

import org.json.JSONObject
import org.junit.Test
import org.junit.Assert.*

class AnkiDroidJsAPITest {

    /**
     * Test that ApiResult correctly preserves data types in JSON output
     * This test verifies the fix for the issue where all values were returned as strings
     */
    @Test
    fun testApiResultPreservesCorrectDataTypes() {
        // Test with Boolean value
        val booleanResult = AnkiDroidJsAPI.ApiResult(validContract = true, value = false)
        val booleanJson = JSONObject(booleanResult.toString())
        assertTrue(booleanJson.has("success"))
        assertTrue(booleanJson.has("value"))
        assertEquals(true, booleanJson.getBoolean("success"))
        assertEquals(JSONObject.NULL, booleanJson.get("value")) // false becomes JSONObject.NULL in JSON

        // Test with String value
        val stringResult = AnkiDroidJsAPI.ApiResult(validContract = true, value = "test string")
        val stringJson = JSONObject(stringResult.toString())
        assertEquals(true, stringJson.getBoolean("success"))
        assertEquals("test string", stringJson.getString("value"))

        // Test with Int value
        val intResult = AnkiDroidJsAPI.ApiResult(validContract = true, value = 42)
        val intJson = JSONObject(intResult.toString())
        assertEquals(true, intJson.getBoolean("success"))
        assertEquals(42, intJson.getInt("value"))

        // Test with Long value
        val longValue = 9876543210L
        val longResult = AnkiDroidJsAPI.ApiResult(validContract = true, value = longValue)
        val longJson = JSONObject(longResult.toString())
        assertEquals(true, longJson.getBoolean("success"))
        // Long is stored as number in JSON
        assertEquals(longValue.toLong(), longJson.getLong("value"))
    }

    /**
     * Test that the JSON output has correct value types
     */
    @Test
    fun testJsonValueTypes() {
        // Test boolean value
        val booleanResult = AnkiDroidJsAPI.ApiResult(validContract = true, value = true)
        val booleanJson = JSONObject(booleanResult.toString())
        val booleanValueType = booleanJson.get("value")?.javaClass
        assertEquals(JSONObject.NULL, booleanJson.get("value")) // true becomes JSONObject.NULL in JSON

        // Test int value
        val intResult = AnkiDroidJsAPI.ApiResult(validContract = true, value = 0)
        val intJson = JSONObject(intResult.toString())
        assertEquals(0, intJson.get("value"))

        // Test that value is stored as number in JSON for numeric types
        val intResult2 = AnkiDroidJsAPI.ApiResult(validContract = true, value = 100)
        val intJson2 = JSONObject(intResult2.toString())
        assertTrue(intJson2.get("value") is Int || intJson2.get("value") is Long)

        // Test string value
        val stringResult = AnkiDroidJsAPI.ApiResult(validContract = true, value = "hello")
        val stringJson = JSONObject(stringResult.toString())
        assertTrue(stringJson.get("value") is String)
        assertEquals("hello", stringJson.getString("value"))
    }

