     */
    @Test
    fun testCardQueueReturnsNumber() {
        val cardQueueValue = 0 // Typical new card queue value
        val result = AnkiDroidJsAPI.ApiResult(validContract = true, value = cardQueueValue)
        val json = JSONObject(result.toString())

        // Verify the value is a number in JSON
        val value = json.get("value")
        assertTrue(value is Int || value is Long)
        assertEquals(cardQueueValue, (value as Number).toInt())
    }

